import React, { Fragment, useState } from "react";
import {
  BrowserRouter as Router,
  Route,
  Routes,
  Navigate,
} from "react-router-dom";

//routes/components
import Home from "./routes/Home";
import Login from "./routes/Login";
import Registration from "./routes/Registration";

const App = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  return (
    <Fragment>
      <Router>
        <Routes>
          <Route path="/" Component={Home} />
          <Route
            path="/login"
            Component={Login}
            render={(props) =>
              !isAuthenticated ? <Login {...props} /> : <Navigate to="/Home" />
            }
          />
          <Route
            path="/registration"
            Component={Registration}
            render={(props) => !isAuthenticated ?<Registration {...props} /> : <Navigate to="/Home" />}
          />
        </Routes>
      </Router>
      {/* Hello  */}
    </Fragment>
  );
};
export default App;
